var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"네바다주 제 16 이터니움 반응로 실험기지     \\n<color=#ffd34c>델타 세븐</color> 카린 웡","JPN":"ネバダ州、第16エタニウム反応炉の実験基地     \\n<color=#ffd34c>デルタセブン</color>カリン・ウォン","ENG":"Nevada Eternium Reactor Test Area 16    \\n<color=#ffd34c>Delta Seven</color> Karin Wong","TWN":"內華達州第16永恆之金反應爐實驗基地  \\n<color=#ffd34c>第七三角洲部隊</color> 卡琳"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"크로스로드 작전 수행 중","JPN":"クロスロード作戦を遂行中","ENG":"During Operation Crossroads","TWN":"十字路口作戰中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……그보다 이제부터 차원 통로 연결을 시작할 겁니다.","JPN":"……それより、これから次元間通路への接続を開始します。","ENG":"By the way, I'm going to establish a dimensional passage from now on.","TWN":"現在馬上就要開始連接次元通道了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"도중에 침식체들이 난입했다간 파장이 흐트러져서 임무가 실패로 돌아갈 수 있어요.","JPN":"途中で侵食体たちに乱入されたら、波長が乱れて任務が失敗に終わるかもしれません。","ENG":"And I can't have C.O.s interfering with the frequency, or our mission will fail.","TWN":"如果途中有侵蝕體入侵，有可能會擾亂波長，導致任務失敗。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 더 이상의 다이브는 우리 힘으로 불가능해요.","JPN":"これ以上のダイブは、私たちの力では不可能です。","ENG":"We can't dive any deeper on our own.","TWN":"現在憑我們的力量無法再進行躍入。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"억지로 시도했다간 둘 다 차원의 미아가 되고, 임무는 중단되어 버리겠죠.","JPN":"強引に進めたら、二人とも次元の間で迷子になり、任務は中止になるでしょうね。","ENG":"If we force it, we will get lost in some unknown dimension before we accomplish our mission.","TWN":"強行嘗試的話，我們二個都會迷失在次元中，任務就徹底終止了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까...... 그러니까 여기서......","JPN":"ですから……ですから、ここで……","ENG":"So... So, we must...","TWN":"所以......所以這裡......"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......여기서, 반드시 끝을 내야 해요.","JPN":"……ここで、必ず決着をつけないと。","ENG":"We must finish it right here and now.","TWN":"......在這裡，必須要成功。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 아이스크림 따위에 정신 팔지 말고 방어선을 유지하는 데 집중하세요.","JPN":"だから、アイスなんかに気を取られてる場合じゃありません。防御線の維持に集中してください。","ENG":"So, forget the ice cream and focus on maintaining the defense line.","TWN":"請不要被區區霜淇淋吸引注意力，集中精神維持防線。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알겠습니까?","JPN":"いいですね？","ENG":"Get it?","TWN":"明白了嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨? 왜 대답이 없죠? 또 제 얘기가 듣기 싫다고 자는 척하는 건가요?","JPN":"シノンさん？　どうして答えないんですか？　また真面目に聞かずに、寝てるフリでもしてるんですか？","ENG":"Shiyoung? Why aren't you answering me? Are you pretending to sleep again because you don't want to hear me?","TWN":"時雨？為什麼不回答？又在裝睡嗎，這麼不想聽我的話？"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 미안해요. 카린 양. 손님이 온 것 같아요.","JPN":"あ、ごめんなさい、カリンさん。お客さんが来てるみたいです。","ENG":"Oh, I'm sorry, Karin, but I think I've got company.","TWN":"啊，對不起。卡琳。好像來客人了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"손님? 시설에서 부른 지원군인가요?","JPN":"お客さん？　施設から要請した援軍ですか？","ENG":"Company? Are they reinforcements from the base?","TWN":"客人？是設施呼叫的援軍嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"글쎄요......","JPN":"どうでしょう……","ENG":"I don't know…","TWN":"這個......"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"잘은 몰라도 여유 부릴 만한 상대가 아닌 것 같네요.","JPN":"よくわかりませんが、そう簡単な相手ではなさそうです。","ENG":"I'm not sure, but they're not easy to deal with.","TWN":"雖然不太清楚，但似乎不是能從容應對的對手呢。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐가 됐든 빨리 끝내세요. 제 느낌상 오래 버티진 못할 것 같거든요.","JPN":"とにかく早く済ませてください。私の勘だと、そう長くは持ちこたえられないので。","ENG":"You'd better finish whatever you're doing quickly. I don't think I can hold them off for too long.","TWN":"總之，請快點結束吧。我感覺自己應該撐不了太久。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 통신 끊습니다.","JPN":"では、通信を切りますね。","ENG":"Now, over and out.","TWN":"那我就結束通訊了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨? 주시영 씨?","JPN":"シノンさん？　アキヤマ・シノンさん？","ENG":"Shiyoung? Joo Shiyoung!","TWN":"時雨？時……周時雨？"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐야, 자기 멋대로 끊어버렸잖아!?","JPN":"そんな、勝手に切られた！？","ENG":"What? She just hung up without my reply!","TWN":"什麼啊，竟然擅自掛斷通訊？！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"쳇, 이래서 용병들이란…….","JPN":"ったく、なんで傭兵はみんなこうなの……","ENG":"Tch, you rude mercenaries...","TWN":"傭兵果真是沒紀律……"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋아, 분석 능력으로 작동 원리는 대충 간파했어.","JPN":"よし、分析能力を使って動作原理は大体把握できたわ。","ENG":"All right, I got a rough idea of how this works with my analytical skills.","TWN":"很好，根據我的分析，大致明白啟動原理了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"반응로 점화 카운트다운. 3, 2, 1……!","JPN":"反応炉点火のカウントダウン。3、2、1……！","ENG":"Reactor ignition in 3, 2, 1...!","TWN":"反應堆點火倒計時。3、2、1……！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이터니움 반응로 점화!","JPN":"エタニウム反応炉点火！","ENG":"Igniting the reactor!","TWN":"點火！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋아, 차원 통로 연결 확인!","JPN":"よし、次元通路へ繋がった！","ENG":"Okay, dimensional passage connection confirmed!","TWN":"好，確認次元通道連接！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_BALISADA_SKILL_LOOP"},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"들리세요? 사이버 캣? 사이버 캣!","JPN":"聞こえますか？　サイバーキャット？　サイバーキャット！","ENG":"Hello? Cyber Cat, can you hear me? Cyber Cat!","TWN":"聽得到嗎？賽博貓？賽博貓！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"이제야 연결됐네!","JPN":"やっと繋がったわね！","ENG":"Finally! Loud and clear!","TWN":"終於連接上了！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L48_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"대체 뭐하다 이렇게 늦은 거야, 잔소리 소령!","JPN":"何やってたのよ！　遅いじゃない、小言少佐！","ENG":"What took you so long, Major Nag?!","TWN":"你們到底幹什麼去了，這麼晚才聯繫，嘮叨鬼少校！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그게…… 사정이 좀 있었어요.","JPN":"それが……色々あったもので。","ENG":"Well... There was some stuff I had to take care of.","TWN":"那個……出了點狀況。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그보다 대령님은!? 대령님은 무사한가요?","JPN":"それより大佐は！？　大佐はご無事なんですか？","ENG":"But what about Colonel?! Is he okay?","TWN":"先不說這個，上校呢？！他還好嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"대령은 지금 필사적으로 네피림의 움직임을 막고 있어.","JPN":"大佐は今、必死にネフィリムを食い止めているわ。","ENG":"Colonel's doing everything he can to stop the Nephil.","TWN":"上校他正在拼命地阻擋諾菲力的行動。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"작전대로 이쪽에서 신호를 보내면 대령이 연결된 차원 통로로 네피림을 유도할 거야.","JPN":"作戦通りにこちらから合図を送れば、繋がった次元通路に大佐がネフィリムを誘導する。","ENG":"When we give the signal just like we planned, Colonel's gonna lure the Nephil to the dimensional passage.","TWN":"按照作戰計畫，這邊發送信號後，上校將會把諾菲力引誘至已連接的次元通道。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님…….","JPN":"大佐……","ENG":"Colonel...","TWN":"上校……"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"아아, 언제까지 그렇게 답답하게 굴 거야, 진짜!?","JPN":"もう、いつになったら素直になる気！？　まったく！","ENG":"Ugh, you're being so frustrating!","TWN":"啊啊啊啊，你怎麼還磨磨唧唧的？！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그냥 대령이랑 직접 연결해 줄 테니까, 하고 싶은 말 있으면 직접 하든가!","JPN":"いっそ直接大佐に繋げるから、話したいこと話せば？","ENG":"I'll just connect you directly to him, so you can say whatever is on your mind!","TWN":"我給你接通上校，有什麼想說的話，親自跟他說！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"에, 에엣!? 사, 사, 사이버캣!?","JPN":"え、ええっ！？　さ、サイバーキャット！？","ENG":"W-what?! C-Cyber Cat?!","TWN":"嗯，呃呃？！賽，賽，賽博貓？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐, 잠깐만요!","JPN":"ちょ、ちょっと待ってください！","ENG":"W-wait, wait!","TWN":"等等，等一下！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이쪽에서도 육안으로 차원 통로를 확인했다, 소령.","JPN":"こちらからも肉眼で次元通路を確認した、少佐。","ENG":"Major, I got eyes on the dimensional passage.","TWN":"少校，我在這邊也看到次元通道了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"잘해주었다. 지금부터 그쪽으로 네피림을 유도하지.","JPN":"よくやった。今からそちらにネフィリムを誘導する。","ENG":"Good work. I'll lure the Nephil over there.","TWN":"你做的很好。現在我會將諾菲力引誘到那裡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님은……! 대령님은 무사하신가요!?","JPN":"大佐は……！　大佐はご無事なんですか！？","ENG":"Colonel...! Are you all right, sir?!","TWN":"上校……！你沒事吧？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이 정도 상처는, 아무것도 아니야.","JPN":"この程度はかすり傷だ。","ENG":"It's nothing. Just a flesh wound.","TWN":"這種小傷，不算什麼。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그냥 잠시…… 잠시 숨을 돌리고 있었을 뿐이야.","JPN":"ただしばらく……一息ついていただけだ。","ENG":"I just... need some time to catch my breath.","TWN":"我只是暫時……暫時喘口氣而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그렇지만!","JPN":"で、ですが！","ENG":"B-but!","TWN":"可，可是！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그만. 말했을 텐데?","JPN":"よせ。言ったはずだ。","ENG":"Enough. Have I not made myself clear?","TWN":"好了，我應該跟你說過吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"군인이라면 임무를 위해 마지막까지 냉철함을 유지하라고.","JPN":"軍人たるもの任務のために、最後まで冷静さを保てと。","ENG":"We soldiers must remain cool-headed while on our missions.","TWN":"身為軍人，為了任務要始終保持冷靜。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 명심하겠습니다.","JPN":"はい、肝に銘じます。","ENG":"Understood, sir.","TWN":"是！我明白了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그보다 초고심도의 이면 세계는 어떻지? 역시 예상대로 아무것도 없는 세계인가?","JPN":"ところで、超高深度の裏世界はどうだ？　やはり思ったとおり、何もない世界か？","ENG":"By the way, how is the hyperdepths of Counterside? Is it a world of nothingness, like we assumed?","TWN":"話說回來，在超深度的異界裡的體驗如何？和我們預想的一樣，是個荒蕪的世界嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이곳에는 아무것도 없습니다.","JPN":"こちらには何もありません。","ENG":"There's nothing over here.","TWN":"是，這裡什麼都沒有。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니 저희를 믿고 작전을 속행해주세요, 대령님.","JPN":"ですから、私たちに任せて作戦を続けてください。大佐。","ENG":"So, trust me and proceed with the plan, Colonel.","TWN":"所以上校，請相信我們，繼續執行計畫吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그렇군, 그렇다면 안심하고 저 괴물을 안고 떨어질 수 있겠군.","JPN":"そうか、ならば安心してあの化け物を抱えて飛び込めそうだ。","ENG":"Very well. Then I can take this monster with me there with peace of mind.","TWN":"這樣啊，那我就可以放心地抱著怪物跳進去了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋아. 그럼, 자네들에게 마지막 임무를 내리도록 하지.","JPN":"よろしい。では、君たちに最後の任務を課す。","ENG":"Okay, then this will be the last order I give you all.","TWN":"好了。聽好，這是我給你們下達的最後任務。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님!? 대령님!! 방금 무슨!?","JPN":"大佐！？　大佐！！　今のご発言はいったい！？","ENG":"Colonel?! Colonel!! What was that sound?!","TWN":"上校？！上校！！剛剛那句話是什麼意思？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"커흑!! 이제 시간이 없어! 마지막 임무다, 카린!","JPN":"くっ！！　もう時間がない！　最後の任務だ、カリン！","ENG":"Gaaagh!! There isn't much time! Karin, this is your last mission!","TWN":"咳咳！！現在時間不多了！這是最後的任務，卡琳！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님?","JPN":"大佐？","ENG":"Colonel?","TWN":"上校？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"긍지 높은 델타 세븐의 일원으로서……","JPN":"誇り高きデルタセブンの一員として……","ENG":"As a proud member of Delta Seven...","TWN":"我要你作為榮耀第七三角洲部隊的一員……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"살아라……!","JPN":"生き延びろ……！","ENG":"Live...!","TWN":"活下去……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"마지막의…… 마지막 순간까지…… 포기하지 말고 반드시 살아남아라!","JPN":"最後の……最後の瞬間まで……諦めずに必ず生き延びろ！","ENG":"Until... the very last second... Don't give up and survive no matter what!","TWN":"你要堅持……到最後一刻……不能放棄，一定要活下去！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"살아서…… 우리의 세계를……!","JPN":"生きて……俺たちの世界を……！","ENG":"Survive... and protect–","TWN":"活下去……拯救我們的世……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"subtitle","speaker":null,"text":{"KOREA":"크로스로드 작전 성공, 3개월 뒤","JPN":"クロスロード作戦成功から3か月後","ENG":"3 months after the success of Operation Crossroads","TWN":"十字路口作戰成功3個月後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 지구 본부, 임시 국립 묘지","JPN":"人類統合防衛軍第1地区本部、臨時国立墓地","ENG":"Provisional National Cemetery, United Humankind Defense Force, 1st District HQ","TWN":"人類共同保衛軍第一區總部，臨時公墓"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"……도미닉 킹 레지날드 대원.","JPN":"……ドミニーク・キング・レジナルド隊員。","ENG":"...Dominic King Reginald.","TWN":"……多明尼克隊員。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"애드 맥케인 대원, 브라이언 리 대원, 알리야 호넷 대원, 애들린 매드슨 대원……","JPN":"エド・マケイン隊員、ブライアン・リー隊員、アリヤ・ホーネット隊員、アデリン・マドソン隊員……","ENG":"Ed McCain, Brian Lee, Aliya Hornet, Adalyn Madson...","TWN":"埃德·麥凱恩隊員、布萊恩·李隊員、阿利婭·霍內斯隊員、艾德琳·麥德森隊員……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"……제이크 워커 대원.","JPN":"……ジェイク・ウォーカー隊員。","ENG":"...Jake Walker.","TWN":"……傑克·沃克隊員。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그리고 그 외 네피림으로부터 세계를 수호하기 위해 산화한 수많은 대원들.","JPN":"そして、その他にもネフィリムから世界を守るために戦死した数多の隊員たち。","ENG":"And the rest of all the troops who sacrificed their lives to protect this world from the Nephil.","TWN":"以及其他為了守護世界被諾菲力殺害的眾多隊員們。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"우리는 그들이 벌어준 소중한 시간을 결코 헛되이 사용해서는 안 됩니다.","JPN":"我々は彼らによってもたらされたこの時間を決して無駄にしてはならない。","ENG":"The precious time they bought us must not go to waste.","TWN":"我們絕不能白白浪費他們用生命爭取來的寶貴時間。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"또한 우리들은 국민으로서, 전우로서, 그리고 인간으로서.","JPN":"また、我々は国民として、戦友として、そして人として。","ENG":"Furthermore, as citizens of this nation, as comrades, and as fellow human beings.","TWN":"而我們作為國民、作為戰友、作為人類。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그들의 고귀한 죽음을 잊어서도 안 됩니다.","JPN":"彼らの誇り高き死を、忘れてはならない。","ENG":"We shall not forget their noble deaths.","TWN":"要銘記他們的英勇就義。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"앞서 간 대원들의 숭고한 희생과 평안한 안식을 위해, 경례.","JPN":"先立った隊員たちの崇高なる犠牲と平穏な安息のために、敬礼。","ENG":"We shall honor their noble sacrifice. May they rest in peace.","TWN":"為那些犧牲的隊員們崇高的犧牲與安息，敬禮。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"부대 차려!","JPN":"全体、気をつけ！","ENG":"Attention!","TWN":"全員立正！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"경례!","JPN":"敬礼！","ENG":"Present arms!","TWN":"敬禮！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_EXILER_NPC_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GUARD_EXILER_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"보고 계세요, 대령님?","JPN":"見ていますか、大佐？","ENG":"Are you watching over us, Colonel?","TWN":"你看到了嗎，上校？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님의 명령대로 저, 살아남았어요.","JPN":"大佐の命令通り、私は生き延びました。","ENG":"I'm still alive, just like you ordered.","TWN":"我遵照你的命令，活下來了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 앞으로도 살 수 있을 때까지 최선을 다해 살아남겠습니다.","JPN":"そして、これからも全力で生き抜いてみせます。","ENG":"And I'll do my best to survive for as long as I can.","TWN":"而且，以後也會努力地活下去。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저도 당신처럼 마지막 순간이 닥칠 때까지 절대로 포기하지 않을 테니까.","JPN":"私もあなたのように、最後の瞬間まで決して諦めません。","ENG":"Like you, I will never give up until the last moment.","TWN":"我會像你一樣，直到最後一刻也絕不放棄。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까…… 그러니까 그곳에서 계속 지켜봐주세요.","JPN":"ですから……どうか向こうでも見守っていてください。","ENG":"So... So please, keep watching over us from there.","TWN":"所以……所以請你在那邊一直看著吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"앞서 간 대원들, 그리고 당신이 지켜낸 이 세계를.","JPN":"戦死した仲間たち、そしてあなたが守ってみせたこの世界を。","ENG":"Watch over our fallen comrades and the world you saved.","TWN":"看著那些犧牲的隊員們，以及你守護的這個世界。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};